import React, { useState } from 'react';
import { X } from 'lucide-react';
import { useAuth } from '../utils/AuthContext';
const inputStyle = { padding:'14px 16px', background:'var(--bg-elevated)', border:'1px solid rgba(255,255,255,0.1)', borderRadius:8, color:'var(--text-base)', fontSize:15, outline:'none', width:'100%' };
export default function AuthModal({ onClose }) {
  const [mode, setMode] = useState('login');
  const [form, setForm] = useState({ username:'', email:'', password:'' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { login, register } = useAuth();
  const handle = async (e) => {
    e.preventDefault(); setError(''); setLoading(true);
    try { mode === 'login' ? await login(form.email, form.password) : await register(form.username, form.email, form.password); onClose(); }
    catch (err) { setError(err.response?.data?.error || 'Something went wrong'); }
    finally { setLoading(false); }
  };
  return (
    <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.8)', display:'flex', alignItems:'center', justifyContent:'center', zIndex:1000, backdropFilter:'blur(8px)' }}>
      <div style={{ background:'var(--bg-highlight)', borderRadius:16, padding:40, width:400, position:'relative', boxShadow:'0 24px 64px rgba(0,0,0,0.5)' }}>
        <button onClick={onClose} style={{ position:'absolute', top:16, right:16, background:'none', border:'none', color:'var(--text-subdued)', cursor:'pointer' }}><X size={20}/></button>
        <div style={{ textAlign:'center', marginBottom:32 }}>
          <div style={{ fontSize:40, marginBottom:8 }}>🎵</div>
          <h2 style={{ fontSize:24, fontWeight:800, color:'var(--text-base)' }}>{mode === 'login' ? 'Log in to MoodTune' : 'Create your account'}</h2>
        </div>
        <form onSubmit={handle} style={{ display:'flex', flexDirection:'column', gap:16 }}>
          {mode === 'register' && <input style={inputStyle} placeholder="Username" value={form.username} onChange={e => setForm({...form, username:e.target.value})} required/>}
          <input style={inputStyle} type="email" placeholder="Email address" value={form.email} onChange={e => setForm({...form, email:e.target.value})} required/>
          <input style={inputStyle} type="password" placeholder="Password" value={form.password} onChange={e => setForm({...form, password:e.target.value})} required/>
          {error && <p style={{ color:'#e91429', fontSize:14, textAlign:'center' }}>{error}</p>}
          <button type="submit" disabled={loading} style={{ padding:'14px', borderRadius:30, background:'var(--essential-bright)', border:'none', color:'black', fontWeight:800, fontSize:15, cursor:loading?'not-allowed':'pointer', opacity:loading?0.7:1, marginTop:8 }}>
            {loading ? '...' : mode === 'login' ? 'Log In' : 'Sign Up'}
          </button>
        </form>
        <div style={{ textAlign:'center', marginTop:24 }}>
          <p style={{ color:'var(--text-subdued)', fontSize:14 }}>
            {mode === 'login' ? "Don't have an account? " : 'Already have an account? '}
            <span onClick={() => { setMode(mode==='login'?'register':'login'); setError(''); }} style={{ color:'var(--essential-bright)', cursor:'pointer', fontWeight:700 }}>
              {mode === 'login' ? 'Sign up' : 'Log in'}
            </span>
          </p>
        </div>
      </div>
    </div>
  );
}
